using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change #1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve it.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change #2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|<id>", so we must opt back in.
            b.HasPartitionKey(blog => blog.Id);
            b.Property(blog => blog.Id)
                .HasJsonPropertyName("id")
                .ToJsonProperty("id");
            b.UseIdWithDiscriminatorInKey();

            // Breaking change #3: EF 9 removed HasIndex support for Cosmos.
            // Indexes are managed via Cosmos DB directly, not EF.
            // Removed: b.HasIndex(blog => blog.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

